+/**
+ * Audit logging service for the notification system.
+ *
+ * Records every notification dispatched, including which channel
+ * was used and the notification priority. Provides query methods
+ * for retrieving audit entries.
+ */
+
+import type { NotificationPriority } from '../events/event-types.js';
+import type { NotificationChannel } from './notification-preferences.service.js';
+
+export interface AuditLogEntry {
+  id: string;
+  timestamp: Date;
+  recipient: string;
+  subject: string;
+  body: string;
+  priority: NotificationPriority;
+  channel: NotificationChannel;
+}
+
+let nextAuditId = 1;
+
+function generateAuditId(): string {
+  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
+}
+
+export function resetAuditIdCounter(): void {
+  nextAuditId = 1;
+}
+
+export class AuditService {
+  private entries: AuditLogEntry[] = [];
+
+  record(params: {
+    recipient: string;
+    subject: string;
+    body: string;
+    priority: NotificationPriority;
+    channel: NotificationChannel;
+  }): AuditLogEntry {
+    const entry: AuditLogEntry = {
+      id: generateAuditId(),
+      timestamp: new Date(),
+      recipient: params.recipient,
+      subject: params.subject,
+      body: params.body,
+      priority: params.priority,
+      channel: params.channel,
+    };
+    this.entries.push(entry);
+    return entry;
+  }
+
+  getEntries(): AuditLogEntry[] {
+    return [...this.entries];
+  }
+
+  getEntriesForRecipient(recipient: string): AuditLogEntry[] {
+    return this.entries.filter((e) => e.recipient === recipient);
+  }
+
+  getEntriesByChannel(channel: NotificationChannel): AuditLogEntry[] {
+    return this.entries.filter((e) => e.channel === channel);
+  }
+
+  getEntriesByPriority(priority: NotificationPriority): AuditLogEntry[] {
+    return this.entries.filter((e) => e.priority === priority);
+  }
+
+  getEntryCount(): number {
+    return this.entries.length;
+  }
+
+  clear(): void {
+    this.entries = [];
+  }
+}

