import type { NotificationSendEvent, NotificationPriority } from '../events/event-types.js';
import type { NotificationChannelHandler } from './notification.service.js';
import type { NotificationChannel } from './notification-preferences.service.js';
import { Logger } from '../utils/logger.js';

export interface PriorityRouteMap {
  urgent: NotificationChannelHandler;
  normal: NotificationChannelHandler;
  low: NotificationChannelHandler;
}

export class PriorityRouter {
  private logger = new Logger('PriorityRouter');
  private routes: PriorityRouteMap;
  private channelMap: Map<NotificationChannel, NotificationChannelHandler>;

  constructor(routes: PriorityRouteMap) {
    this.routes = routes;
    this.channelMap = new Map<NotificationChannel, NotificationChannelHandler>([
      ['sms', routes.urgent],
      ['email', routes.normal],
      ['webhook', routes.low],
    ]);
  }

  async route(event: NotificationSendEvent): Promise<NotificationChannel> {
    const channel = this.channelForPriority(event.priority);
    const handler = this.routes[event.priority];
    if (!handler) {
      this.logger.error(`No handler registered for priority: ${event.priority}`);
      throw new Error(`No handler registered for priority: ${event.priority}`);
    }

    this.logger.info(
      `Routing ${event.priority} notification to ${event.recipient} via ${channel}`,
    );

    await handler.handle(event);
    return channel;
  }

  async routeToChannel(channel: NotificationChannel, event: NotificationSendEvent): Promise<void> {
    const handler = this.channelMap.get(channel);
    if (!handler) {
      this.logger.error(`No handler registered for channel: ${channel}`);
      throw new Error(`No handler registered for channel: ${channel}`);
    }

    this.logger.info(
      `Routing notification to ${event.recipient} via ${channel} (user preference)`,
    );

    await handler.handle(event);
  }

  channelForPriority(priority: NotificationPriority): NotificationChannel {
    switch (priority) {
      case 'urgent':
        return 'sms';
      case 'normal':
        return 'email';
      case 'low':
        return 'webhook';
    }
  }
}

