/**
 * Send a notification. When a PriorityRouter is configured, routes to the
 * appropriate channel based on priority (or user preference if set).
 * Otherwise falls back to broadcasting via EventBus for backward compatibility.
 * Records an audit log entry when an AuditService is configured.
 */
private sendNotification(params: {
  recipient: string;
  subject: string;
  body: string;
  priority?: NotificationPriority;
}): void {
  const priority = params.priority ?? 'normal';
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: new Date(),
  };
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${notification.id} to ${params.recipient} [${priority}]`);

  const event: NotificationSendEvent = {
    type: 'notification:send',
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    priority,
    timestamp: new Date(),
  };

  if (this.priorityRouter) {
    const userPreference = this.preferencesService?.getPreference(params.recipient);

    if (userPreference) {
      // User preference overrides priority-based routing
      this.logger.info(
        `User preference override: routing to ${userPreference} for ${params.recipient}`,
      );
      this.priorityRouter.routeToChannel(userPreference, event);
      this.auditService?.record({
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        priority,
        channel: userPreference,
      });
    } else {
      // Route based on priority; route() returns the channel used
      const channel = this.priorityRouter.channelForPriority(priority);
      this.priorityRouter.route(event);
      this.auditService?.record({
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        priority,
        channel,
      });
    }
  } else {
    // Legacy broadcast: publish to EventBus so all channel handlers deliver
    this.eventBus.emit(event);
  }
}

