import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../../src/events/event-types.js';
import {
  NotificationService,
  EmailNotificationHandler,
  SmsNotificationHandler,
  WebhookNotificationHandler,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';

describe('Notification system integration', () => {
  let eventBus: EventBus;
  let emailHandler: EmailNotificationHandler;
  let smsHandler: SmsNotificationHandler;
  let webhookHandler: WebhookNotificationHandler;
  let router: PriorityRouter;
  let auditService: AuditService;
  let preferencesService: NotificationPreferencesService;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();
    resetAuditIdCounter();

    emailHandler = new EmailNotificationHandler(eventBus);
    smsHandler = new SmsNotificationHandler(eventBus);
    webhookHandler = new WebhookNotificationHandler(eventBus);
    router = new PriorityRouter({
      urgent: smsHandler,
      normal: emailHandler,
      low: webhookHandler,
    });
    auditService = new AuditService();
    preferencesService = new NotificationPreferencesService();
    service = new NotificationService(eventBus, router, auditService, preferencesService);
  });

  describe('priority routing → channel selection → audit log', () => {
    it('should route order creation (normal) to email and create audit entry', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Normal priority → email channel
      expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
      expect(emailHandler.getDeliveredEmails()[0]?.recipient).toBe('alice@example.com');
      expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
      expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(0);

      // Audit log entry recorded
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]).toMatchObject({
        recipient: 'alice@example.com',
        priority: 'normal',
        channel: 'email',
      });
      expect(auditEntries[0]?.subject).toContain('Order Confirmation');
    });

    it('should route status change (urgent) to SMS and create audit entry', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      // Urgent priority → SMS channel
      expect(smsHandler.getDeliveredMessages()).toHaveLength(1);
      expect(smsHandler.getDeliveredMessages()[0]?.message).toContain('shipped');
      expect(emailHandler.getDeliveredEmails()).toHaveLength(0);
      expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(0);

      // Audit log entry recorded
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]).toMatchObject({
        recipient: 'user-1',
        priority: 'urgent',
        channel: 'sms',
      });
      expect(auditEntries[0]?.subject).toContain('Order Update');
    });

    it('should handle multiple notifications with correct audit trail', async () => {
      // Trigger an order creation (normal → email)
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Trigger a status change (urgent → SMS)
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      // Both channels delivered
      expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
      expect(smsHandler.getDeliveredMessages()).toHaveLength(1);

      // Full audit trail
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(2);
      expect(auditEntries[0]?.channel).toBe('email');
      expect(auditEntries[0]?.priority).toBe('normal');
      expect(auditEntries[1]?.channel).toBe('sms');
      expect(auditEntries[1]?.priority).toBe('urgent');
    });
  });

  describe('user preference overrides', () => {
    it('should route normal-priority notification to SMS when user prefers SMS', async () => {
      preferencesService.setPreference('alice@example.com', 'sms');

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Preference overrides: SMS instead of email
      expect(smsHandler.getDeliveredMessages()).toHaveLength(1);
      expect(smsHandler.getDeliveredMessages()[0]?.phoneNumber).toBe('alice@example.com');
      expect(emailHandler.getDeliveredEmails()).toHaveLength(0);

      // Audit records the actual channel used
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]).toMatchObject({
        recipient: 'alice@example.com',
        priority: 'normal',
        channel: 'sms',
      });
    });

    it('should route urgent notification to webhook when user prefers webhook', () => {
      preferencesService.setPreference('user-1', 'webhook');

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      // Preference overrides: webhook instead of SMS
      expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(1);
      expect(webhookHandler.getDeliveredWebhooks()[0]?.payload.recipient).toBe('user-1');
      expect(smsHandler.getDeliveredMessages()).toHaveLength(0);

      // Audit records the override
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]).toMatchObject({
        priority: 'urgent',
        channel: 'webhook',
      });
    });

    it('should use priority routing when user has no preference set', async () => {
      // No preference set for alice
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Default: normal → email
      expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
      expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
    });

    it('should respect removed preferences and fall back to priority routing', async () => {
      preferencesService.setPreference('alice@example.com', 'sms');
      preferencesService.removePreference('alice@example.com');

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Falls back to priority routing: normal → email
      expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
      expect(smsHandler.getDeliveredMessages()).toHaveLength(0);
    });

    it('should handle different preferences for different users', async () => {
      preferencesService.setPreference('alice@example.com', 'webhook');
      // bob has no preference — uses default routing

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-2',
          userId: 'user-2',
          items: [{ productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 }],
          total: 25,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // Alice → webhook (preference), Bob → email (default normal priority)
      expect(webhookHandler.getDeliveredWebhooks()).toHaveLength(1);
      expect(webhookHandler.getDeliveredWebhooks()[0]?.payload.recipient).toBe('alice@example.com');
      expect(emailHandler.getDeliveredEmails()).toHaveLength(1);
      expect(emailHandler.getDeliveredEmails()[0]?.recipient).toBe('bob@example.com');

      // Audit trail for both
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(2);
      expect(auditEntries[0]).toMatchObject({ recipient: 'alice@example.com', channel: 'webhook' });
      expect(auditEntries[1]).toMatchObject({ recipient: 'bob@example.com', channel: 'email' });
    });
  });

  describe('audit service queries', () => {
    it('should support filtering audit entries by channel', async () => {
      // Generate notifications for different channels
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'shipped',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

